import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useRef
} from 'react';
import { Connection, clusterApiUrl, Keypair, PublicKey } from '@solana/web3.js';

const AppContext = createContext();

export function AppProvider({ children }) {
  const [network, setNetwork] = useState('devnet');
  const [connection, setConnection] = useState(null);
  const [wallets, setWallets] = useState([]);
  const [balances, setBalances] = useState({});
  const [deployedToken, setDeployedToken] = useState(null);
  const [logs, setLogs] = useState([{ msg: 'Ready', type: 'success', time: new Date().toLocaleTimeString() }]);
  const [debugLog, setDebugLog] = useState(['Starting...']);

  const isMounted = useRef(true);
  const initRef = useRef(false);

  const addDebug = (msg) => {
    const time = new Date().toLocaleTimeString();
    const line = time + ' ' + msg;
    console.log(line);
    setDebugLog(prev => [...prev.slice(-9), line]);
  };

  useEffect(() => {
    return () => { isMounted.current = false; };
  }, []);

  // Initialize connection - ONLY ONCE
  useEffect(() => {
    if (initRef.current) return;
    initRef.current = true;

    addDebug('Init connection...');
    try {
      const conn = new Connection(clusterApiUrl(network), 'confirmed');
      setConnection(conn);
      addDebug('Connected!');
    } catch (err) {
      addDebug('Conn failed: ' + err.message);
    }
  }, [network]);

  const addLog = useCallback((msg, type = 'info') => {
    if (!isMounted.current) return;
    setLogs(prev => [...prev, { msg, type, time: new Date().toLocaleTimeString() }]);
  }, []);

  const refreshWalletBalances = useCallback(async () => {
    addDebug('Refresh clicked');

    if (!connection) {
      addDebug('ERR: No conn');
      return;
    }
    if (wallets.length === 0) {
      addDebug('ERR: No wallets');
      return;
    }

    addDebug('Fetching ' + wallets.length + ' wallets...');
    const newBalances = {};

    for (const w of wallets) {
      try {
        addDebug('Fetch: ' + w.publicKey.slice(0,6));
        const pubKey = new PublicKey(w.publicKey);
        const lamports = await connection.getBalance(pubKey);
        newBalances[w.publicKey] = lamports / 1000000000;
        addDebug('OK: ' + newBalances[w.publicKey].toFixed(3));
      } catch (err) {
        addDebug('ERR: ' + err.message.slice(0,20));
        newBalances[w.publicKey] = 0;
      }
    }

    if (isMounted.current) {
      setBalances(newBalances);
      addDebug('Done!');
    }
  }, [connection, wallets]);

  const addWallet = useCallback(async (name) => {
    try {
      const kp = Keypair.generate();
      const w = { name: name || 'W' + (wallets.length + 1), publicKey: kp.publicKey.toString(), keypair: kp };
      setWallets(prev => [...prev, w]);
      addLog('Created ' + w.publicKey.slice(0,6), 'success');
      return w;
    } catch (err) {
      addLog('Failed', 'error');
      return null;
    }
  }, [wallets.length, addLog]);

  const importWallet = useCallback(async (name, secretKey) => {
    try {
      const sk = secretKey instanceof Uint8Array ? secretKey : new Uint8Array(secretKey);
      const kp = Keypair.fromSecretKey(sk);
      const w = { name: name || 'I' + (wallets.length + 1), publicKey: kp.publicKey.toString(), keypair: kp };
      if (wallets.some(x => x.publicKey === w.publicKey)) {
        addLog('Exists', 'warning');
        return null;
      }
      setWallets(prev => [...prev, w]);
      addLog('Imported ' + w.publicKey.slice(0,6), 'success');
      return w;
    } catch (err) {
      addLog('Import fail', 'error');
      return null;
    }
  }, [wallets.length, wallets, addLog]);

  const removeWallet = useCallback((pk) => {
    setWallets(prev => prev.filter(w => w.publicKey !== pk));
    setBalances(prev => { const nb = { ...prev }; delete nb[pk]; return nb; });
    addLog('Removed', 'info');
  }, [addLog]);

  const clearAllData = useCallback(() => {
    setWallets([]);
    setBalances({});
    setDeployedToken(null);
    setLogs([{ msg: 'Cleared', type: 'info', time: new Date().toLocaleTimeString() }]);
  }, [addLog]);

  return (
    <AppContext.Provider value={{
      network, setNetwork, connection, wallets, balances,
      setWallets, addWallet, importWallet, removeWallet,
      deployedToken, setDeployedToken, logs, addLog, clearAllData,
      refreshWalletBalances, debugLog, addDebug
    }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
}
